var findLHS = function(nums) {
    const c = new Map();
    for (const x of nums) c.set(x, (c.get(x) || 0) + 1);
    let best = 0;
    for (const [v, n] of c) {
        if (c.has(v + 1)) best = Math.max(best, n + c.get(v + 1));
    }
    return best;
};
